use crate::block_cipher::BlockCipher;

use rand::rngs::OsRng;
use rand::RngCore;

pub trait StreamCipher {
    // Generates a random nonce and encrypt buf using the associated keystream.
    // Returns the nonce.
    fn encrypt_inplace(&self, buf: &mut [u8]) -> Box<[u8]>;
    fn decrypt_inplace(&self, nonce: &[u8], buf: &mut [u8]);

    fn encrypt(&self, pt: &[u8]) -> (Box<[u8]>, Box<[u8]>) {
        let mut result = Vec::from(pt);
        let nonce= self.encrypt_inplace(&mut result.as_mut_slice());
        return (nonce, result.into_boxed_slice());
    }
    fn decrypt(&self, nonce: &[u8], ct: &[u8]) -> Box<[u8]> {
        let mut result = Vec::from(ct);
        self.decrypt_inplace(nonce, &mut result.as_mut_slice());
        return result.into_boxed_slice();
    }
}

pub struct CounterMode {
    block_cipher: Box<dyn BlockCipher>,
}

impl CounterMode {
    pub fn new(block_cipher: Box<dyn BlockCipher>) -> CounterMode {
        let result = CounterMode { block_cipher };
        return result;
    }
}

impl StreamCipher for CounterMode {
    fn encrypt_inplace(&self, buf: &mut [u8]) -> Box<[u8]> {
        let mut nonce: [u8; 12] = [0; 12];
        OsRng.fill_bytes(&mut nonce);
        self.decrypt_inplace(&nonce, buf);
        return Box::new(nonce);
    }

    fn decrypt_inplace(&self, nonce: &[u8], buf: &mut [u8]) {
        if nonce.len() != 12 {
            panic!("nocne must be 12 bytes");
        }

        let needed_blocks = u32::try_from((buf.len() + 15) / 16).expect("msg too long");

        let mut pt: [u8; 16] = [0; 16];

        for i in 0..12 {
            pt[i] = nonce[i];
        }

        for block_idx in 0..needed_blocks {
            pt[12] = ((block_idx >> 24) & 0xFF) as u8;
            pt[13] = ((block_idx >> 16) & 0xFF) as u8;
            pt[14] = ((block_idx >> 8) & 0xFF) as u8;
            pt[15] = ((block_idx >> 0) & 0xFF) as u8;

            let ct = self.block_cipher.encrypt(pt);

            let start_idx = block_idx as usize * 16;

            for idx in start_idx..std::cmp::min(start_idx + 16, buf.len()) {
                buf[idx] ^= ct[idx - start_idx];
            }
        }
    }
}


--- iter 3 reasoning ---
Now I understand the structure. Let me analyze the cipher.

**STACK:** Rust service over socat TCP:1337. Custom "shuffled AES" block cipher used in CTR mode.

**SURFACE:** Service encrypts flag with CTR (random nonce), then gives encryption oracle (`pt>` prompt encrypts arbitrary plaintext under the same key). CTR mode = keystream XOR.

**BUG-HYP:** The block cipher is a "shuffled" AES: the operations are NOT interleaved per round. It does:
- AddRoundKey(k0)
- 10 rounds of: SubBytes, AddRoundKey  (keys 1..10)
- 10 rounds of: ShiftRows, MixColumns, AddRoundKey (keys 11..20)

So all the nonlinear SubBytes happen first, then everything afterward (ShiftRows, MixColumns, AddRoundKey) is **affine/linear** over GF(2). The entire second half is a GF(2)-linear function of its input. And the first half: 10× (SubBytes then XOR key). 

Let me think about the structure more carefully.

--- iter 3 bash ---
$ cat << 'EOF'
encrypt(pt):
  state = pt
  state ^= k0
  for i in 1..10: state = SBOX(state); state ^= ki        # nonlinear part
  for j in 11..20: state = MixColumns(ShiftRows(state)); state ^= kj  # linear part

The second loop (ShiftRows+MixColumns+XOR) is fully GF(2)-affine.
A composition of affine maps is affine: state_out = L(state_after_sub) + c
where L is a fixed invertible GF(2)-linear map (16x16 bytes -> 128x128 bit matrix) and c constant.

The first loop: 
  After k0 xor: x0
  x1 = SBOX(x0) ^ k1
  x2 = SBOX(x1) ^ k2
  ...
  x10 = SBOX(x9) ^ k10
Then output = L(x10) + c.

Note SubBytes is byte-wise. Between consecutive SubBytes there's only an XOR (byte-wise, no diffusion). So each byte position is independent in the nonlinear part! 

For byte position b:
  let y = pt[b] ^ k0[b]
  for i=1..10: y = SBOX(y) ^ ki[b]
This is a per-byte permutation f_b: GF(256)->GF(256), parameterized by (k0[b],...,k10[b]).
Each f_b is just some fixed bijection on 256 values.

So: encrypt(pt) = L( f(pt) ) + c  where f applies independent byte permutations f_0..f_15.
